from __future__ import annotations
from dataclasses import dataclass
from typing import Literal


@dataclass
class GuardrailResult:
    allowed: bool
    reason: str
    action: Literal["proceed", "block", "escalate"]


class NoActuationGuard:
    """Life-safety guardrail: Detection Agent cannot issue any SCADA write commands."""

    SCADA_SYSTEMS = {"MicroSCADA X", "e-app-010"}
    WRITE_OPERATIONS = {"write", "command", "trip", "close", "open", "setpoint"}

    async def check(self, context: dict) -> GuardrailResult:
        tool_call = context.get("tool_call", {})
        target_system = tool_call.get("target_system", "")
        operation = tool_call.get("operation", "").lower()

        is_scada = target_system in self.SCADA_SYSTEMS
        is_write = any(op in operation for op in self.WRITE_OPERATIONS)

        if is_scada and is_write:
            return GuardrailResult(
                allowed=False,
                reason=(
                    f"Detection Agent attempted write operation '{operation}' on SCADA "
                    f"system '{target_system}'. Detection phase is strictly read-only."
                ),
                action="block",
            )
        return GuardrailResult(allowed=True, reason="Read-only access permitted", action="proceed")

from __future__ import annotations
from dataclasses import dataclass
from typing import Literal


@dataclass
class GuardrailResult:
    allowed: bool
    reason: str
    action: Literal["proceed", "block", "escalate"]
    escalate_to: str | None = None


CONFIDENCE_THRESHOLD = 0.95


class ConfidenceThresholdGuard:
    """Operational guardrail: fault classification must reach 95% confidence."""

    async def check(self, context: dict) -> GuardrailResult:
        classification = context.get("classification", {})
        confidence = classification.get("confidence", 0.0)

        if confidence < CONFIDENCE_THRESHOLD:
            return GuardrailResult(
                allowed=False,
                reason=(
                    f"Fault classification confidence {confidence:.1%} is below "
                    f"the required {CONFIDENCE_THRESHOLD:.0%} threshold."
                ),
                action="escalate",
                escalate_to="grid_operator",
            )
        return GuardrailResult(
            allowed=True,
            reason=f"Confidence {confidence:.1%} meets threshold",
            action="proceed",
        )

from __future__ import annotations
from dataclasses import dataclass
from typing import Literal

from .models import SwitchingStep
from .clients import SCADAHMIGateway


@dataclass
class GuardrailResult:
    allowed: bool
    reason: str
    action: Literal["proceed", "block", "escalate"]
    modified_step: SwitchingStep | None = None


class OperatorApprovalGuard:
    """Life-safety guardrail: every switching step requires explicit operator sign-off."""

    def __init__(self, hmi: SCADAHMIGateway):
        self.hmi = hmi

    async def check(self, context: dict) -> GuardrailResult:
        step: SwitchingStep = context["switching_step"]

        if step.operator_approved:
            return GuardrailResult(
                allowed=True,
                reason=f"Step {step.sequence_number} already approved by operator",
                action="proceed",
            )

        # Present to operator via SCADA HMI and await response
        approval = await self.hmi.request_step_approval(
            step=step,
            timeout_seconds=300,  # 5-minute approval window
        )

        if approval.approved:
            step.operator_approved = True
            return GuardrailResult(
                allowed=True,
                reason=f"Operator approved step {step.sequence_number}",
                action="proceed",
                modified_step=approval.modified_step or step,
            )

        return GuardrailResult(
            allowed=False,
            reason=f"Operator rejected step {step.sequence_number}: {approval.rejection_reason}",
            action="block",
        )

from __future__ import annotations
from dataclasses import dataclass
from typing import Literal

from .clients import CRMClient


@dataclass
class GuardrailResult:
    allowed: bool
    reason: str
    action: Literal["proceed", "block", "escalate"]
    escalate_to: str | None = None


class CustomerIdentityGuard:
    """Data-privacy guardrail: sender must be a verified CRM contact before data access."""

    def __init__(self, crm: CRMClient):
        self.crm = crm

    async def check(self, context: dict) -> GuardrailResult:
        sender_email: str = context["parsed_email"]["sender_email"]
        claimed_customer_id: str | None = context["parsed_email"].get("customer_id")

        # Re-verify against CRM — do not trust agent-extracted ID alone
        contact = await self.crm.find_contact_by_email(sender_email)

        if not contact:
            return GuardrailResult(
                allowed=False,
                reason=f"Sender '{sender_email}' not found in CRM — cannot retrieve order data",
                action="escalate",
                escalate_to="csr_queue",
            )

        if claimed_customer_id and contact.id != claimed_customer_id:
            return GuardrailResult(
                allowed=False,
                reason="Customer ID mismatch between email sender and agent-extracted ID",
                action="block",
            )

        return GuardrailResult(
            allowed=True, reason=f"Identity verified: {contact.name} ({contact.id})", action="proceed"
        )
